:root {
    --aq-light: 185, 235, 255;
    --aq-soft: 135, 215, 245;
    --aq-mid: 95, 185, 225;
    --aq-deep: 35, 95, 145;
    --aq-dark: 18, 45, 80;
    --body-font: 'Quicksand', sans-serif;
    --header-font: 'Comfortaa', cursive;
    --mono-font: 'Fantasque Sans Mono', monospace;
}

.page-container .page {
    border: 2px solid rgba(var(--aq-soft), 0.45);
    margin: 12px auto;
    border-radius: 24px;
    background: rgba(var(--aq-dark), 0.55);
    backdrop-filter: blur(10px);
    box-shadow: 0 0 20px rgba(var(--aq-soft), 0.12);
}

.theme-fandomdesktop-dark,
.theme-fandomdesktop-light {
    --theme-page-background-color: rgba(var(--aq-dark), 0.45);
    --theme-page-background-color--secondary: rgba(var(--aq-deep), 0.35);
    --theme-link-color: rgb(var(--aq-light));
    --theme-border-color: rgba(var(--aq-soft), 0.4);
    --theme-community-header-color: rgb(var(--aq-light));
    --theme-sticky-nav-background-color: rgba(var(--aq-dark), 0.7);
    --theme-sticky-nav-text-color: rgb(var(--aq-light));
    --theme-sticky-nav-text-color--hover: rgb(var(--aq-soft));
}

a,
a:visited {
    color: rgb(var(--aq-light)) !important;
    text-decoration: none;
    transition: color 0.3s ease, text-shadow 0.3s ease;
}

a:hover,
a:focus {
    color: rgb(var(--aq-soft)) !important;
    text-shadow: 0 0 10px rgba(var(--aq-soft), 0.5);
}

.page-side-tools .page-side-tool {
    border: 2px solid rgba(var(--aq-soft), 0.45);
    border-radius: 50%;
    background: rgba(var(--aq-mid), 0.2);
    backdrop-filter: blur(6px);
    box-shadow: 0 0 12px rgba(var(--aq-soft), 0.15);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.page-side-tool:hover {
    transform: scale(1.08);
    box-shadow: 0 0 18px rgba(var(--aq-light), 0.3);
}

.titleblock,
.dark-titleblock {
    background: linear-gradient(
        180deg,
        rgba(var(--aq-soft), 0.25),
        rgba(var(--aq-deep), 0.35)
    );
    border: 2px solid rgba(var(--aq-light), 0.45);
    border-radius: 28px;
    padding: 1rem;
    font-family: var(--header-font);
    font-weight: 700;
    color: rgb(var(--aq-light));
    text-shadow: 0 0 10px rgba(var(--aq-light), 0.35);
    font-size: 2.3em;
    letter-spacing: 2px;
    animation: water-glow 5s ease-in-out infinite alternate;
    box-shadow: 0 0 20px rgba(var(--aq-soft), 0.15);
}

.progress {
    background: rgba(var(--aq-dark), 0.45);
    border: 2px solid rgba(var(--aq-soft), 0.4);
    border-radius: 16px;
    color: rgb(var(--aq-light));
    overflow: hidden;
}

.progress .bar {
    background: linear-gradient(
        90deg,
        rgba(var(--aq-soft), 0.7),
        rgba(var(--aq-light), 0.85)
    );
    border-radius: 14px;
    box-shadow: 0 0 12px rgba(var(--aq-light), 0.25);
}

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--header-font);
    color: rgb(var(--aq-light));
    letter-spacing: 3px;
    text-shadow: 0 0 10px rgba(var(--aq-soft), 0.3);
    font-size: calc(1.5rem + 0.6vw);
}

h1 {
    font-size: calc(2rem + 1.2vw);
}

blockquote {
    background: rgba(var(--aq-mid), 0.15);
    border-left: 4px solid rgba(var(--aq-light), 0.6);
    border-radius: 12px;
    backdrop-filter: blur(6px);
}

table.wiki-content-table {
    background: rgba(var(--aq-dark), 0.35);
    border: 2px solid rgba(var(--aq-soft), 0.35);
    border-radius: 16px;
}

table.wiki-content-table th {
    background: rgba(var(--aq-mid), 0.35);
    color: rgb(var(--aq-light));
}

table.wiki-content-table td {
    background: rgba(var(--aq-dark), 0.25);
}

@keyframes water-glow {
    0% {
        box-shadow: 0 0 12px rgba(var(--aq-soft), 0.12);
        text-shadow: 0 0 8px rgba(var(--aq-soft), 0.2);
    }

    100% {
        box-shadow: 0 0 24px rgba(var(--aq-light), 0.22);
        text-shadow: 0 0 14px rgba(var(--aq-light), 0.4);
    }
}
}}
